@page "/category/{CategorySlug}"

<PageTitle>@CategoryName - RecipeHub</PageTitle>

<h1>@CategoryEmoji @CategoryName</h1>
<p class="lead">@CategoryDescription</p>

<div class="list-group">
    @foreach (var recipe in Recipes)
    {
        <a href="/recipe/@recipe.Slug" class="list-group-item list-group-item-action">
            <div class="d-flex w-100 justify-content-between">
                <h5 class="mb-1">@recipe.Title</h5>
                <small>@recipe.PrepTime</small>
            </div>
            <p class="mb-1">@recipe.Summary</p>
        </a>
    }
</div>

<div class="mt-3">
    <a href="/" class="btn btn-secondary">← Back to Categories</a>
</div>

@code {
    [Parameter]
    public string CategorySlug { get; set; } = "";

    private string CategoryName => CategorySlug switch
    {
        "appetizers" => "Appetizers",
        "main-courses" => "Main Courses",
        "desserts" => "Desserts",
        "beverages" => "Beverages",
        "baking" => "Baking",
        "vegetarian" => "Vegetarian",
        _ => "Recipes"
    };

    private string CategoryEmoji => CategorySlug switch
    {
        "appetizers" => "🥗",
        "main-courses" => "🍝",
        "desserts" => "🍰",
        "beverages" => "🥤",
        "baking" => "🍞",
        "vegetarian" => "🥬",
        _ => "🍽️"
    };

    private string CategoryDescription => CategorySlug switch
    {
        "appetizers" => "Light bites and starters to kick off any meal.",
        "main-courses" => "Hearty dishes for lunch and dinner.",
        "desserts" => "Sweet treats to end your meal on a high note.",
        "beverages" => "Refreshing drinks, smoothies, and cocktails.",
        "baking" => "Breads, pastries, and baked goods from scratch.",
        "vegetarian" => "Meat-free meals packed with flavor.",
        _ => "Browse our collection of recipes."
    };

    private List<RecipeListItem> Recipes => GetRecipesForCategory(CategorySlug);

    private List<RecipeListItem> GetRecipesForCategory(string slug)
    {
        return slug switch
        {
            "appetizers" => new()
            {
                new("bruschetta", "Classic Bruschetta", "Toasted bread with fresh tomatoes and basil", "15 min"),
                new("stuffed-mushrooms", "Stuffed Mushrooms", "Mushroom caps filled with herbed cream cheese", "30 min"),
                new("spring-rolls", "Vegetable Spring Rolls", "Crispy rolls with fresh vegetables", "25 min")
            },
            "main-courses" => new()
            {
                new("spaghetti-carbonara", "Spaghetti Carbonara", "Classic Italian pasta with eggs, cheese, and pancetta", "25 min"),
                new("chicken-tikka", "Chicken Tikka Masala", "Creamy spiced chicken in tomato sauce", "45 min"),
                new("beef-stew", "Hearty Beef Stew", "Slow-cooked beef with root vegetables", "2 hrs")
            },
            "desserts" => new()
            {
                new("chocolate-cake", "Chocolate Lava Cake", "Rich molten chocolate cake with a gooey center", "35 min"),
                new("tiramisu", "Classic Tiramisu", "Italian coffee-flavored layered dessert", "4 hrs"),
                new("apple-pie", "Homestyle Apple Pie", "Flaky crust filled with cinnamon apples", "1.5 hrs")
            },
            "beverages" => new()
            {
                new("mango-smoothie", "Mango Smoothie", "Tropical mango blended with yogurt", "5 min"),
                new("iced-matcha", "Iced Matcha Latte", "Creamy green tea over ice", "5 min"),
                new("berry-lemonade", "Berry Lemonade", "Fresh lemonade with mixed berries", "10 min")
            },
            "baking" => new()
            {
                new("sourdough-bread", "Sourdough Bread", "Artisan bread with a tangy flavor", "24 hrs"),
                new("cinnamon-rolls", "Cinnamon Rolls", "Soft rolls with cream cheese frosting", "2.5 hrs"),
                new("banana-bread", "Banana Bread", "Moist bread with ripe bananas and walnuts", "1 hr")
            },
            "vegetarian" => new()
            {
                new("veggie-stir-fry", "Veggie Stir Fry", "Colorful vegetables in garlic soy sauce", "20 min"),
                new("mushroom-risotto", "Mushroom Risotto", "Creamy arborio rice with wild mushrooms", "40 min"),
                new("falafel-bowl", "Falafel Bowl", "Crispy falafel with hummus and fresh veggies", "35 min")
            },
            _ => new()
        };
    }

    private record RecipeListItem(string Slug, string Title, string Summary, string PrepTime);
}

@rendermode InteractiveServer

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var starValue = i;
        <span class="star @(starValue <= CurrentRating ? "filled" : "")"
              @onclick="() => SetRating(starValue)"
              role="button"
              title="@starValue star(s)">
            @(starValue <= CurrentRating ? "★" : "☆")
        </span>
    }
    @if (CurrentRating > 0)
    {
        <span class="ms-2 text-muted">You rated this @CurrentRating/5</span>
    }
</div>

<style>
    .star {
        font-size: 1.5rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.2s;
    }
    .star:hover,
    .star.filled {
        color: #ffc107;
    }
</style>

@code {
    [Parameter]
    public string RecipeSlug { get; set; } = "";

    private int CurrentRating { get; set; }

    private void SetRating(int rating)
    {
        CurrentRating = rating;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📝 Submit Your Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@Model.Title</strong>" with the RecipeHub community.</p>
        <a href="/" class="btn btn-primary">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="Model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="Model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="appetizers">Appetizers</option>
                <option value="main-courses">Main Courses</option>
                <option value="desserts">Desserts</option>
                <option value="beverages">Beverages</option>
                <option value="baking">Baking</option>
                <option value="vegetarian">Vegetarian</option>
            </InputSelect>
            <ValidationMessage For="() => Model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="Model.Ingredients" class="form-control" rows="6"
                placeholder="One ingredient per line, e.g.:&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="Model.Steps" class="form-control" rows="6"
                placeholder="One step per line, e.g.:&#10;Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
        <a href="/" class="btn btn-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    private RecipeSubmission Model { get; set; } = new();
    private bool IsSubmitted { get; set; }

    private void HandleSubmit()
    {
        IsSubmitted = true;
    }

    private class RecipeSubmission
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be 100 characters or fewer.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = "";
    }
}

